            answer[i] = 0;
            continue;
        }

        int maxLCP = 0;
        // Check the pairs that are affected by removing i
        // The affected pairs are (i-1, i) and (i, i+1) in the original array
        // After removal, the new pair is (i-1, i+1) if i is not at the boundary

        // Iterate through all adjacent pairs in the modified array
        // The modified array is words[0..i-1] + words[i+1..n-1]
        // So adjacent pairs are:
        // 0..i-2: same as original
        // i-1 and i (original i+1) if i > 0 and i < n-1
        // i..n-2: original i+1..n-1 shifted left by 1

        int currentMax = 0;
        for (int j = 0; j < n - 1; j++) {
            if (j == i - 1) {
                // This is the new pair formed by words[j] and words[j+1] (original j and j+2)
                if (j + 1 < n - 1) {
                    int lcp = computeLCP(words[j], words[j + 2]);
                    if (lcp > currentMax) {
                        currentMax = lcp;
                    }
                }
                j++; // Skip the next original pair as it's removed
            } else if (j == i) {
                // Skip this pair as it's removed
                continue;
            } else {
                // Use the precomputed LCP
                int originalIndex = j;
                if (j > i) {
                    originalIndex = j + 1;
                }
                if (originalIndex < originalLCP.length) {
                    int lcp = originalLCP[originalIndex];
                    if (lcp > currentMax) {
                        currentMax = lcp;
                    }
                }
            }
        }
        answer[i] = currentMax;
    }

    return answer;
}

private static int computeLCP(String a, String b) {
    int minLen = Math.min(a.length(), b.length());
    int lcp = 0;
    for (int i = 0; i < minLen; i++) {
        if (a.charAt(i) == b.charAt(i)) {
            lcp++;
        } else {
            break;
        }
    }
    return lcp;
