    int[] originalLCP = new int[n - 1];
    for (int i = 0; i < n - 1; i++) {
        originalLCP[i] = computeLCP(words[i], words[i + 1]);
    }

    for (int i = 0; i < n; i++) {
        int maxLCP = 0;
        // Iterate through all adjacent pairs in the modified array
        for (int j = 0; j < n - 1; j++) {
            if (j == i - 1) {
                // This pair is (words[j], words[j+2]) after removing words[i] (i = j+1)
                if (j + 2 < n) {
                    int lcp = computeLCP(words[j], words[j + 2]);
                    if (lcp > maxLCP) {
                        maxLCP = lcp;
                    }
                }
            } else if (j == i) {
                // Skip this pair as it's removed
                continue;
            } else {
                // The pair is (words[j], words[j+1]) if j < i, or (words[j+1], words[j+2]) if j > i
                // But in the modified array, the indices are shifted if j >= i
                int left = j < i ? j : j + 1;
                int right = left + 1;
                if (right >= n) {
