public static long[] solve(String[] words) {
    int n = words.length;
    long[] answer = new long[n];

    if (n == 1) {
        return answer;
    }

    // Precompute the LCP for adjacent pairs in the original array
    int[] originalLCP = new int[n - 1];
    for (int i = 0; i < n - 1; i++) {
        originalLCP[i] = computeLCP(words[i], words[i + 1]);
    }

    for (int i = 0; i < n; i++) {
        if (n == 2) {
            // Only one adjacent pair remains after removal
            if (i == 0) {
                answer[i] = computeLCP(words[1], words[2 >= n ? 1 : 2]);
            } else {
                answer[i] = computeLCP(words[0], words[1 >= n ? 0 : 1]);
            }
        } else {
            int maxLCP = 0;
            // Check the new adjacent pair formed by i-1 and i+1 when i is removed
            if (i > 0 && i < n - 1) {
                int newLCP = computeLCP(words[i - 1], words[i + 1]);
                maxLCP = Math.max(maxLCP, newLCP);
            }
            // Check the original adjacent pairs not involving i
            // Pairs before i
            for (int j = 0; j < i - 1; j++) {
                maxLCP = Math.max(maxLCP, originalLCP[j]);
            }
            // Pairs after i
            for (int j = i + 1; j < n - 1; j++) {
                maxLCP = Math.max(maxLCP, originalLCP[j]);
            }
            answer[i] = maxLCP;
        }
    }

    return answer;
}

private static int computeLCP(String a, String b) {
    int minLen = Math.min(a.length(), b.length());
    int lcp = 0;
    while (lcp < minLen && a.charAt(lcp) == b.charAt(lcp)) {
        lcp++;
    }
    return lcp;
