                continue;
            } else if (j + 1 == i) {
                if (j + 2 < n) {
                    // The pair (j, j+2) is now adjacent
                    int lcp = computeLCP(words[j], words[j + 2]);
                    if (lcp > maxLCP) {
                        maxLCP = lcp;
                    }
                }
            } else {
                // The original adjacent pair is still present
                if (j < originalLCP.length) {
                    if (originalLCP[j] > maxLCP) {
                        maxLCP = originalLCP[j];
                    }
                }
            }
        }
        answer[i] = maxLCP;
    }

    return answer;
